import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{t as i}from"./chunks/idea-community.CV-Uvcck.js";const a=JSON.parse(`{"title":"设置开发环境","description":"关于如何搭建 Fabric 开发环境的逐步指南。","frontmatter":{"title":"设置开发环境","description":"关于如何搭建 Fabric 开发环境的逐步指南。","authors":["2xsaiko","Andrew6rant","asiekierka","Daomephsta","falseresync","IMB11","liach","mkpoli","modmuss50","natanfudge","SolidBlock-cn","TelepathicGrunt"],"authors-nogithub":["siglong"],"files":[]},"headers":[],"relativePath":"zh_cn/1.21.8/develop/getting-started/setting-up-a-development-environment.md","filePath":"versions/1.21.8/translated/zh_cn/develop/getting-started/setting-up-a-development-environment.md","lastUpdated":1760721669000}`);var o={name:`zh_cn/1.21.8/develop/getting-started/setting-up-a-development-environment.md`};function s(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">设置开发环境 <a class="header-anchor" href="#h1" aria-label="Permalink to “设置开发环境”">​</a></h1><p>要开始使用 Fabric 开发模组，需要使用 IntelliJ IDEA 设置开发环境。</p><h2 id="installing-jdk-21" tabindex="-1">安装 JDK 21 <a class="header-anchor" href="#installing-jdk-21" aria-label="Permalink to “安装 JDK 21”">​</a></h2><p>要开发 Minecraft 1.21.4 的模组，需要 JDK 21。</p><p>如果需要安装 Java 方面的帮助，可以参考<a href="./../../players/index">玩家指南部分</a>中的各种 Java 安装指南。</p><h2 id="installing-intellij-idea" tabindex="-1">安装 IntelliJ IDEA <a class="header-anchor" href="#installing-intellij-idea" aria-label="Permalink to “安装 IntelliJ IDEA”">​</a></h2><div class="info custom-block"><p class="custom-block-title custom-block-title-default">INFO</p><p>你显然可以使用其他 IDE， 比如 Eclipse 或 Visual Studio Code，但本文档站点上的大多数页面都假定你使用的是 IntelliJ IDEA - 如果你使用的是其他 IDE，则应参考那些 IDE 的文档。</p></div><p>如果没有安装 IntelliJ IDEA，可以从<a href="https://www.jetbrains.com/idea/download/" target="_blank" rel="noreferrer">官方网站</a>下载 - 按照你的操作系统的安装步骤操作。</p><p>IntelliJ IDEA 的社区版是免费且开源的，是使用 Fabric 开发模组的推荐版本。</p><p>你可能需要向下滚动才能找到社区版下载链接 - 如下所示：</p><p><img src="/assets/develop/getting-started/idea-community.png" alt="IDEA 社区版下载提示" loading="lazy"></p><h2 id="installing-idea-plugins" tabindex="-1">安装 IDEA 插件 <a class="header-anchor" href="#installing-idea-plugins" aria-label="Permalink to “安装 IDEA 插件”">​</a></h2><p>这些插件虽然不是绝对必要的，但可以让使用 Fabric 开发模组更容易 - 应该要考虑安装。</p><h3 id="minecraft-development" tabindex="-1">Minecraft Development <a class="header-anchor" href="#minecraft-development" aria-label="Permalink to “Minecraft Development”">​</a></h3><p>Minecraft Development 插件为使用 Fabric 开发模组提供支持，是要安装的最重要的插件。</p><p>如要安装，可以打开 IntelliJ IDEA，然后在搜索栏中导航到 <code>文件 &gt; 设置 &gt; 插件 &gt; Marketplace 标签页</code> - 在搜索框中搜索 <code>Minecraft Development</code>，然后点击 <code>安装</code> 按钮。</p><p>或者你可以从<a href="https://plugins.jetbrains.com/plugin/8327-minecraft-development" target="_blank" rel="noreferrer">插件页面</a>下载，然后依次点击 <code>文件 &gt; 设置 &gt; 插件 &gt; 从硬盘上安装插件</code> 来安装。</p>`,17)]])}var c=r(o,[[`render`,s]]);export{a as __pageData,c as default};